#include<bits/stdc++.h>
using namespace std;
int head[400010],to[400010],nxt[400010],cnt;
void add(int x,int y)
{
    nxt[++cnt]=head[x];
    head[x]=cnt;
    to[cnt]=y;
}
int id[400010],siz[400010],d[400010],son[400010],fa[400010],dfncnt,top[400010],rnk[400010],val[400010];
void dfs1(int x,int f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(int j=head[x];j;j=nxt[j])
    {
        int i=to[j];
        if(i!=f)
        {
            d[i]=d[x]+1;
            fa[i]=x;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(int x,int t)
{
    id[x]=++dfncnt;
    rnk[dfncnt]=x;
    top[x]=t;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(int i=head[x];i;i=nxt[i])
        {
            int v=to[i];
            if(v!=son[x]&&v!=fa[x])
            {
                dfs2(v,v);
            }
        }
    }
}
struct node
{
    int sum,l,r,lson,rson;
}a[800010];
void build(int x,int l,int r)
{
    a[x].l=l,a[x].r=r;
    a[x].sum=-1;
    if(r-l<=1)
    {
        return;
    }
    int mid=((l+r)>>1);
    build(x*2,l,mid);
    build(x*2+1,mid,r);
}
void update(int x,int l,int r)
{
    if(l<=a[x].l&&a[x].r<=r)
    {
        a[x].sum=l;
        return;
    }
    int mid=(a[x].l+a[x].r)/2;
    if(l<mid)
    {
        update(x*2,l,r);
    }
    if(r>mid)
    {
        update(x*2+1,l,r);
    }
    a[x].sum=max(a[x*2].sum,a[x*2+1].sum);
}
int query(int x,int l,int r)
{
    if(l<=a[x].l&&a[x].r<=r)
    {
        return a[x].sum;
    }
    int mid=(a[x].l+a[x].r)/2,ans=-1;
    if(l<mid)
    {
        ans=max(ans,query(x*2,l,r));
    }
    if(r>mid)
    {
        ans=max(ans,query(x*2+1,l,r));
    }
    return ans;
}
int getmax(int u,int v)
{
    int ans=-1;
    while(top[u]!=top[v])
    {
        if(d[u]<d[v])
        {
            swap(u,v);
        }
        ans=query(1,id[top[u]],id[u]+1);
        if(ans!=-1)
        {
            return rnk[ans];
        }
        u=fa[top[u]];
    }
    if(d[u]>d[v])
    {
        swap(u,v);
    }
    return rnk[query(1,id[u],id[v]+1)];
}
int main()
{
    // freopen("D:\\program\\C++\\C++(pro)\\code\\2024\\Nov\\Luogu\\1231.in","r",stdin);
    // freopen("D:\\program\\C++\\C++(pro)\\code\\2024\\Nov\\Luogu\\1231.out","w",stdout);
    int n,q;
    scanf("%d%d",&n,&q);
    for(int i=1;i<n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        add(x,y);
        add(y,x);
    }
    d[1]=1;
    dfs1(1);
    dfs2(1,1);
    build(1,1,n+1);
    update(1,1,2);
    while(q--)
    {
        char op;
        int x;
        cin>>op>>x;
        if(op=='C')
        {
            update(1,id[x],id[x]+1);
        }
        else
        {
            printf("%d\n",getmax(x,1));
        }
    }
    return 0;
}
